import redis

class DynamicCache:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db)

    def execute_lua_script(self, lua_script, key, *args):
        return self.redis_client.eval(
            script=lua_script.encode('utf-8'),
            numkeys=len(key),
            key=key,
            args=args
        )

def main():
    cache = DynamicCache()

    lua_script_code = input("Enter Lua script code: ")
    user_input_key = input("Enter Redis key: ")
    user_input_args = input("Enter Lua script arguments (comma separated): ").split(',')

    result = cache.execute_lua_script(lua_script_code, user_input_key, *user_input_args)
    
    print(result)

if __name__ == "__main__":
    main()